import { _decorator, Component, Node, instantiate, Prefab, Canvas } from 'cc';
const { ccclass, property } = _decorator;

@ccclass('manager')
export class manager extends Component {
    @property(Prefab)
    monsterPrefab: Prefab = null;

    @property(Canvas)
    canvas: Canvas = null;

    @property
    spawnInterval: number = 3;

    private _timer: number = 0;

    protected update(dt: number): void {
        this._timer += dt;
        if (this._timer >= this.spawnInterval) {
            this.spawnMonster();
            this._timer = 0;
        }
    }

    spawnMonster() {
        if (!this.monsterPrefab) return;
        const monster = instantiate(this.monsterPrefab);
        monster.parent = this.node;
        monster.setPosition(0, Math.random() * this.node, 0);
    }

}

